package be.schaubroeck.lpb.rkm.rekenmotor.check;

import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenBedrag;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.Gedetacheerd;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.Ordering;
import org.joda.time.LocalDate;

import java.util.Collection;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.function.Consumer;

public class CheckInhoudingZonderVergoedingen {

    private static final int MTC_CODE = 5401;
    private static final int BIJPASSING_NETTO_CODE = 5801;
    private static final int BIJPASSING_NETTO_EXT = 99;
    private static final int INH_SOCIALE_DIENST_CODE = 5501;
    private static final int INH_SOCIALE_DIENST_EXT = 1;
    private static final int INH_SOCIALE_DIENST_CODE_2 = 5801;
    private static final int INH_SOCIALE_DIENST_EXT_2 = 14;

    public void check(
            Persoon persoon, Rekenmodus rekenModus, List<RekenHoofd> outputs, List<RekenHoofd> bestaanden, RegulManager regulManager) {
        Map<Integer, Opdracht> idToOpdracht = new HashMap<>();
        persoon.getOpdrachten().forEach(x -> idToOpdracht.put(x.getId(), x));
        if (rekenModus != Rekenmodus.VOORSCHOT) {
            Multimap<Opdracht, RekenHoofd> opdrachtToHoofden = ArrayListMultimap.create();
            Consumer<RekenHoofd> consumer = x -> opdrachtToHoofden.put(idToOpdracht.get(x.getOpdracht().getId()), x);
            bestaanden.forEach(consumer);
            outputs.forEach(consumer);
            for (Opdracht opdracht : opdrachtToHoofden.keySet()) {
                checkOpdracht(opdracht, opdrachtToHoofden.get(opdracht), regulManager);
            }
        }
    }

    private void checkOpdracht(Opdracht opdracht, Collection<RekenHoofd> hoofden, RegulManager regulManager) {
        CheckResult result = new CheckResult();
        for (RekenHoofd hoofd : hoofden) {
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                checkLijn(opdracht, lijn, result);
            }
        }
        if (result.bedragInhouding.signum() != 0 && result.hasInhoudingOpRekenLijn && !result.hasNonInhoudingOpRekenLijn) {
            AardKodeExtensie aardKodeExtensie = result.aardKodeExtensies.stream().findFirst().orElse(null);
            String message = "nakijken " + (aardKodeExtensie != null ? aardKodeExtensie.getAard() : null) + '-' +
                    (aardKodeExtensie != null ? aardKodeExtensie.getCode() : null) + '-' + (aardKodeExtensie != null ? aardKodeExtensie.getExtensie() : null);
            regulManager.doRegulException(opdracht, Regulkode.INHOUDING_ZONDER_MAANDTOTAAL, message);
        }
    }

    private void checkLijn(Opdracht opdracht, RekenLijn lijn, CheckResult result) {
        AardKodeExtensie aardKodeExtensie = lijn.getAardKodeExtensie();
        boolean isInhouding = aardKodeExtensie.getAard().equals(AardKodeExt.I_KODE_EXT.getCode());
        boolean isGedetacheerdMtc = isGedetacheerdMtc(opdracht, lijn);
        boolean isInhoudingSocialeDienst = isInhoudingSocialeDienst(aardKodeExtensie);
        boolean isBijpassingNetto = aardKodeExtensie.getCode() == BIJPASSING_NETTO_CODE && aardKodeExtensie.getExtensie() == BIJPASSING_NETTO_EXT;
        result.hasInhoudingOpRekenLijn = result.hasInhoudingOpRekenLijn || (isInhouding && !isGedetacheerdMtc && !isInhoudingSocialeDienst);
        result.hasNonInhoudingOpRekenLijn = result.hasNonInhoudingOpRekenLijn || !isInhouding;
        if (isInhouding && !isGedetacheerdMtc && !isBijpassingNetto && !isInhoudingSocialeDienst) {
            result.bedragInhouding = result.bedragInhouding.add(bepaalBedragInhouding(lijn));
        }
        if (bevatNegatieveRekenbedragenNetto(lijn) && result.hasInhoudingOpRekenLijn && !result.hasNonInhoudingOpRekenLijn) {
            result.aardKodeExtensies.add(aardKodeExtensie);
        }
    }

    private Money bepaalBedragInhouding(RekenLijn lijn) {
        return lijn.getRekenBedragen()
                .stream()
                .filter(x -> x.getBedragType() == RekenBedragType.NETTO)
                .map(RekenBedrag::getBedrag)
                .reduce(Money.ZERO, Money::add);
    }

    private boolean isGedetacheerdMtc(Opdracht opdracht, RekenLijn lijn) {
        AardKodeExtensie aardKodeExtensie = lijn.getAardKodeExtensie();
        LocalDate selectieDatum = Ordering.natural().min(lijn.getEindDatum(), opdracht.getEindDatum());
        selectieDatum = Ordering.natural().max(selectieDatum, opdracht.getBeginDatum());
        Rszppo rszppo = RekenTools.findOpper(opdracht, selectieDatum).getRszppo();
        return !rszppo.getGedetacheerd().equals(Gedetacheerd.NVT.getCode()) && aardKodeExtensie.getCode() == MTC_CODE;
    }

    private boolean isInhoudingSocialeDienst(AardKodeExtensie aardKodeExtensie) {
        Integer code = aardKodeExtensie.getCode();
        Integer extensie = aardKodeExtensie.getExtensie();
        return (code == INH_SOCIALE_DIENST_CODE && extensie == INH_SOCIALE_DIENST_EXT) || (code == INH_SOCIALE_DIENST_CODE_2 && extensie == INH_SOCIALE_DIENST_EXT_2);
    }

    private boolean bevatNegatieveRekenbedragenNetto(RekenLijn lijn) {
        return lijn.getRekenBedragen().stream().filter(x -> x.getBedragType() == RekenBedragType.NETTO).map(RekenBedrag::getBedrag).anyMatch(money -> money.signum() < 0);
    }

    private static class CheckResult {
        boolean hasInhoudingOpRekenLijn = false;
        boolean hasNonInhoudingOpRekenLijn = false;
        Money bedragInhouding = Money.ZERO;
        Set<AardKodeExtensie> aardKodeExtensies = new HashSet<>();
    }

}
